const c = $('Execute Workflow Trigger').first().json;

function safeList(nodeName) {
  try {
    const d = $(nodeName).first().json;
    return Array.isArray(d.list) ? d.list : [];
  } catch(e) { return []; }
}

const products = safeList('HTTP · Get Products');
const orders   = safeList('HTTP · Get Orders');

let block = '';

if (products.length) {
  const lines = products.map(p => {
    let l = `- ${p.name || p.title}`;
    if (p.sku)         l += ` | SKU: ${p.sku}`;
    if (p.price)       l += ` | Price: ${p.currency || 'INR'} ${p.price}`;
    if (p.stock !== undefined) l += ` | Stock: ${p.stock}`;
    if (p.category)    l += ` | Category: ${p.category}`;
    if (p.color)       l += ` | Color: ${p.color}`;
    if (p.size)        l += ` | Size: ${p.size}`;
    if (p.description) l += ` | ${p.description.slice(0, 80)}`;
    return l;
  }).join('\n');
  block += '\n\n## Products\n' + lines;
}

if (orders.length) {
  const lines = orders.map(o => {
    let l = `- Order #${o.order_id || o.id}`;
    if (o.customer_name)  l += ` | Customer: ${o.customer_name}`;
    if (o.order_date)     l += ` | Date: ${o.order_date}`;
    if (o.status)         l += ` | Status: ${o.status}`;
    if (o.total)          l += ` | Total: ${o.currency || 'INR'} ${o.total}`;
    if (o.items)          l += ` | Items: ${o.items}`;
    return l;
  }).join('\n');
  block += '\n\n## Recent Orders\n' + lines;
}

return [{ json: { ...c, ecomContextBlock: block } }];
